from flask import Flask, request, make_response
from onelogin.saml2.auth import OneLogin_Saml2_Auth
from onelogin.saml2.settings import OneLogin_Saml2_Settings
import os

app = Flask(__name__)

def prepare_flask_request(request):
    return {
        'http_host': request.host,
        'server_port': request.environ.get('SERVER_PORT', '443'),
        'script_name': request.environ.get('SCRIPT_NAME', ''),
        'path_info': request.environ.get('PATH_INFO', ''),
        'query_string': request.environ.get('QUERY_STRING', ''),
        'http_referer': request.headers.get('Referer', ''),
        'http_user_agent': request.headers.get('User-Agent', ''),
        'https': 'on' if request.is_secure else 'off'
    }

@app.route('/saml/response', methods=['POST'])
def saml_response():
    req = prepare_flask_request(request)
    auth = OneLogin_Saml2_Auth(req, custom_base_path=os.path.join(os.getcwd(), 'saml'))

    # Create SAML response
    auth.login()
    saml_response = auth.get_last_response()

    # Sign the assertion
    settings = OneLogin_Saml2_Settings()
    settings.set_str('security', 'signing', True)
    settings.set_str('security', 'wantAssertionsSigned', True)

    # Return the SAML response
    response = make_response(saml_response)
    response.headers['Content-Type'] = 'application/xml'
    return response

if __name__ == '__main__':
    app.run(ssl_context='adhoc')